import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

const API = 'https://pizza-story-backend-u6n0.onrender.com';
const LOYALTY_TARGET = 5;

const STATUS_COLORS = {
  pending:         { bg: 'bg-yellow-100', text: 'text-yellow-700', label: 'ממתין' },
  preparing:       { bg: 'bg-blue-100',   text: 'text-blue-700',   label: 'בהכנה' },
  outForDelivery:  { bg: 'bg-purple-100', text: 'text-purple-700', label: 'במשלוח' },
  completed:       { bg: 'bg-green-100',  text: 'text-green-700',  label: 'הושלם' },
};

export default function OrderHistory() {
  const [orders, setOrders]   = useState([]);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();
  const auth = JSON.parse(localStorage.getItem('pizzaAuth') || '{}');

  useEffect(() => {
    if (!auth.phone) { navigate('/login'); return; }
    axios
      .get(`${API}/api/orders/history/${auth.phone}`)
      .then(res =>
        setOrders(res.data.sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt)))
      )
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  const handleReorder = order => {
    localStorage.setItem('cart', JSON.stringify({
      toppings: order.toppings || [],
      total:    order.total || 30,
    }));
    navigate('/cart');
  };

  const loyaltyCount    = orders.length;
  const loyaltyProgress = loyaltyCount % LOYALTY_TARGET;
  const loyaltyPct      = (loyaltyProgress / LOYALTY_TARGET) * 100;
  const ordersUntilNext = loyaltyProgress === 0 && loyaltyCount > 0 ? 0 : LOYALTY_TARGET - loyaltyProgress;
  const freePizzasEarned = Math.floor(loyaltyCount / LOYALTY_TARGET);
  const totalSpent       = orders.reduce((sum, o) => sum + (o.total || 0), 0);

  if (loading) {
    return (
      <div className="max-w-md mx-auto min-h-screen bg-gray-50 pb-20">
        <div className="bg-navy px-5 pt-5 pb-4">
          <h1 className="text-white text-xl font-black">ההזמנות שלי</h1>
        </div>
        <div className="flex flex-col items-center justify-center py-28">
          <div className="text-5xl mb-4 animate-bounce">🍕</div>
          <p className="text-gray-400">טוען הזמנות...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-md mx-auto min-h-screen bg-gray-50 pb-20">

      {/* Navy Header */}
      <div className="bg-navy px-5 pt-5 pb-4">
        <h1 className="text-white text-xl font-black">ההזמנות שלי</h1>
        <p className="text-blue-200 text-xs mt-0.5">
          {orders.length} הזמנות · סה"כ {totalSpent}₪
        </p>
      </div>

      <div className="px-4 pt-4 space-y-4">

        {/* Loyalty Card */}
        <div
          className="rounded-2xl overflow-hidden shadow-md"
          style={{ background: 'linear-gradient(135deg, #006491 0%, #004d6e 100%)' }}
        >
          <div className="p-4">
            <div className="flex items-center justify-between mb-3">
              <div>
                <p className="text-white font-black text-lg">🏆 כרטיס נאמנות</p>
                <p className="text-blue-200 text-xs">כל 5 הזמנות = פיצה חינם!</p>
              </div>
              {freePizzasEarned > 0 && (
                <div className="bg-yellow-400 text-gray-900 text-xs font-black px-3 py-1.5 rounded-full">
                  🍕 ×{freePizzasEarned} נוצלו
                </div>
              )}
            </div>

            {ordersUntilNext === 0 && loyaltyCount > 0 ? (
              <div className="bg-green-400/20 border border-green-400/40 rounded-xl p-3 text-center mb-3">
                <p className="text-green-300 font-black text-base">🎉 מגיעה לך פיצה חינם!</p>
                <p className="text-green-200 text-xs mt-0.5">פנה לעסק לממש את הפרס</p>
              </div>
            ) : (
              <p className="text-white/80 text-sm mb-3">
                עוד <span className="text-white font-black text-lg">{ordersUntilNext}</span> הזמנות לפיצה חינם
              </p>
            )}

            {/* Progress Bar */}
            <div className="w-full bg-white/20 rounded-full h-3 overflow-hidden">
              <div
                className="bg-tomato h-3 rounded-full transition-all duration-700"
                style={{ width: `${ordersUntilNext === 0 && loyaltyCount > 0 ? 100 : loyaltyPct}%` }}
              />
            </div>
            <div className="flex justify-between text-xs text-white/50 mt-1.5">
              <span>{loyaltyProgress}/{LOYALTY_TARGET}</span>
              <span>הזמנות</span>
            </div>

            {/* Pizza dots */}
            <div className="flex gap-2 mt-3">
              {Array.from({ length: LOYALTY_TARGET }).map((_, i) => (
                <div
                  key={i}
                  className={`flex-1 h-2 rounded-full transition-all duration-300 ${
                    i < (ordersUntilNext === 0 && loyaltyCount > 0 ? LOYALTY_TARGET : loyaltyProgress)
                      ? 'bg-tomato'
                      : 'bg-white/20'
                  }`}
                />
              ))}
            </div>
          </div>
        </div>

        {/* Orders List */}
        {orders.length === 0 ? (
          <div className="bg-white rounded-2xl shadow-sm p-8 text-center">
            <div className="text-6xl mb-3">🍕</div>
            <p className="text-xl font-black text-gray-700 mb-2">אין הזמנות עדיין</p>
            <p className="text-gray-400 text-sm mb-6">ההזמנה הראשונה שלך תופיע כאן</p>
            <button
              onClick={() => navigate('/')}
              className="bg-tomato text-white px-7 py-3.5 rounded-2xl font-black shadow-md hover:bg-red-700 transition active:scale-95"
            >
              הזמן עכשיו
            </button>
          </div>
        ) : (
          <div className="space-y-3">
            {orders.map((order, idx) => {
              const s = STATUS_COLORS[order.status] || { bg: 'bg-gray-100', text: 'text-gray-600', label: order.status || '' };
              return (
                <div key={order.id || idx} className="bg-white rounded-2xl shadow-sm p-4 border border-gray-100/80">
                  <div className="flex justify-between items-start mb-2">
                    <div>
                      <span className="font-black text-tomato text-xl">{order.total}₪</span>
                      {order.status && (
                        <span className={`mr-2 text-xs font-bold px-2 py-0.5 rounded-full ${s.bg} ${s.text}`}>
                          {s.label}
                        </span>
                      )}
                    </div>
                    <span className="text-xs text-gray-400">
                      {order.createdAt ? new Date(order.createdAt).toLocaleDateString('he-IL') : ''}
                    </span>
                  </div>

                  <p className="text-sm text-gray-600 mb-1">
                    🍕 {order.toppings?.length > 0 ? order.toppings.join(', ') : 'ללא תוספות'}
                  </p>

                  {(order.address || order.deliveryAddress) && (
                    <p className="text-xs text-gray-400 mb-2">
                      📍 {order.address || order.deliveryAddress}
                    </p>
                  )}

                  <div className="flex items-center justify-between mt-3 pt-3 border-t border-gray-50">
                    <span className="text-xs text-gray-400">
                      {order.paymentMethod === 'cash' ? '💵 מזומן' : '💳 אשראי'}
                    </span>
                    <button
                      onClick={() => handleReorder(order)}
                      className="bg-navy text-white text-xs font-bold px-4 py-2 rounded-xl hover:opacity-90 transition active:scale-95"
                    >
                      🔄 הזמן שוב
                    </button>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}
